    /// <summary>
    /// Выполняет настройку данного типа сущности в модели.
    /// </summary>
    /// <param name="typeBuilder">
    /// Построитель типа.
    /// </param>
    [MethodImpl(MethodImplOptions.AggressiveInlining)]
    internal static void BuildAction([ParameterNoChecks] EntityTypeBuilder<ChannelInfo> typeBuilder)
    {
        //  Установка имени таблицы.
        typeBuilder.ToTable("ChannelInfos");
        
        //  Указание того, как контекст обнаруживает
        //  изменения свойств для экземпляра типа сущности.
        typeBuilder.HasChangeTrackingStrategy(
            //  Свойства помечаются как измененные,
            //  когда сущность вызывает событие PropertyChanged.
            ChangeTrackingStrategy.ChangedNotifications);
        
        //  Настройка идентификатора сущности.
        typeBuilder.HasKey(channelInfo => channelInfo.Id);
        typeBuilder.Property(channelInfo => channelInfo.Id)
            .ValueGeneratedOnAdd();
        typeBuilder.HasIndex(channelInfo => channelInfo.Id);
        
        //  Настройка свойства "Индекс канала в кадре".
        typeBuilder.Property(channelInfo => channelInfo.Index);
        typeBuilder.HasIndex(channelInfo => channelInfo.Index);
        
        //  Настройка свойства "Частота дискретизации канала".
        typeBuilder.Property(channelInfo => channelInfo.Sampling);
        typeBuilder.HasIndex(channelInfo => channelInfo.Sampling);
        
        //  Настройка свойства "Частота среза фильтра канала".
        typeBuilder.Property(channelInfo => channelInfo.Cutoff);
        typeBuilder.HasIndex(channelInfo => channelInfo.Cutoff);
        
        //  Настройка свойства "Количество статистических данных".
        typeBuilder.Property(channelInfo => channelInfo.StatisticsCount);
        typeBuilder.HasIndex(channelInfo => channelInfo.StatisticsCount);
        
        //  Настройка свойства "Количество распределений".
        typeBuilder.Property(channelInfo => channelInfo.DistributionsCount);
        typeBuilder.HasIndex(channelInfo => channelInfo.DistributionsCount);
        
        //  Настройка идентификатора свойства "Кадр регистрации, содержащий канал".
        typeBuilder.Property(channelInfo => channelInfo.FrameId);
        typeBuilder.HasIndex(channelInfo => channelInfo.FrameId);
        
        //  Настройка свойства "Кадр регистрации, содержащий канал".
        typeBuilder.HasOne(channelInfo => channelInfo.Frame)
            .WithMany(frameInfo => frameInfo.Channels)
            .HasForeignKey(channelInfo => channelInfo.FrameId)
            .OnDelete(DeleteBehavior.Cascade)
            .HasConstraintName("FK_ChannelInfos_FrameInfos");
        
        //  Настройка идентификатора свойства "Имя канала".
        typeBuilder.Property(channelInfo => channelInfo.NameId);
        typeBuilder.HasIndex(channelInfo => channelInfo.NameId);
        
        //  Настройка свойства "Имя канала".
        typeBuilder.HasOne(channelInfo => channelInfo.Name)
            .WithMany(channelName => channelName.Channels)
            .HasForeignKey(channelInfo => channelInfo.NameId)
            .OnDelete(DeleteBehavior.NoAction)
            .HasConstraintName("FK_ChannelInfos_ChannelNames");
        
        //  Настройка идентификатора свойства "Единица измерения канала".
        typeBuilder.Property(channelInfo => channelInfo.UnitId);
        typeBuilder.HasIndex(channelInfo => channelInfo.UnitId);
        
        //  Настройка свойства "Единица измерения канала".
        typeBuilder.HasOne(channelInfo => channelInfo.Unit)
            .WithMany(channelUnit => channelUnit.Channels)
            .HasForeignKey(channelInfo => channelInfo.UnitId)
            .OnDelete(DeleteBehavior.NoAction)
            .HasConstraintName("FK_ChannelInfos_ChannelUnits");
        
        //  Настройка ключа "Уникальные индекс канала и кадр регистрации, содержащий канал".
        typeBuilder.HasAlternateKey(channelInfo => new
        {
            channelInfo.Index,
            channelInfo.FrameId,
        });
        
    }
    
